import{_ as a,o,c as r,ae as t}from"./chunks/framework.B6gjLfeO.js";const f=JSON.parse('{"title":"Troubleshooting Link Formatting Errors","description":"","frontmatter":{"title":"Troubleshooting Link Formatting Errors","slug":"troubleshooting-link-formatting-errors"},"headers":[],"relativePath":"account-hub/troubleshooting-link-formatting-errors.md","filePath":"account-hub/troubleshooting-link-formatting-errors.md"}'),i={name:"account-hub/troubleshooting-link-formatting-errors.md"};function n(s,e,d,c,h,l){return o(),r("div",null,[...e[0]||(e[0]=[t('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>During <a href="https://help.branch.io/marketer-hub/docs/testing-ads-campaign-setup" target="_blank" rel="noreferrer">testing</a>, you may run into issues with your Branch Link not being properly formatted or missing information required for accurate routing and attribution.<br> Below you&#39;ll find possible causes for your test link to not work and how to fix the issue.</p><h2 id="aaid-or-idfa-is-not-correctly-formatted" tabindex="-1">AAID or IDFA is not correctly formatted <a class="header-anchor" href="#aaid-or-idfa-is-not-correctly-formatted" aria-label="Permalink to &quot;AAID or IDFA is not correctly formatted&quot;">​</a></h2><h4 id="cause" tabindex="-1">Cause <a class="header-anchor" href="#cause" aria-label="Permalink to &quot;Cause&quot;">​</a></h4><p>Attribution will not occur because the device ID on the link must be in an acceptable IDFA or AAID format, or removed altogether. A common cause for this error is leaving link macros on the link that have not been filled in.</p><h4 id="fix" tabindex="-1">Fix <a class="header-anchor" href="#fix" aria-label="Permalink to &quot;Fix&quot;">​</a></h4><p>Ensure you&#39;re using a real device ID. If you&#39;re testing, use a correctly formatted dummy ID. If you don&#39;t have a device ID and this link is not server to server, you can remove the device ID macro altogether and retest.</p><h2 id="s2s-no-device-id-present" tabindex="-1">S2S &amp; no device ID present <a class="header-anchor" href="#s2s-no-device-id-present" aria-label="Permalink to &quot;S2S &amp; no device ID present&quot;">​</a></h2><h4 id="cause-1" tabindex="-1">Cause <a class="header-anchor" href="#cause-1" aria-label="Permalink to &quot;Cause&quot;">​</a></h4><p>Server to server clicks must have device IDs for attribution. Point in time modeling is not supported for server to server clicks.</p><h4 id="fix-1" tabindex="-1">Fix <a class="header-anchor" href="#fix-1" aria-label="Permalink to &quot;Fix&quot;">​</a></h4><p>Use a device ID macro like <code>$idfa</code> or <code>$aaid</code>.</p><h2 id="s2s-both-idfa-and-aaid" tabindex="-1">S2S &amp; both $idfa AND $aaid <a class="header-anchor" href="#s2s-both-idfa-and-aaid" aria-label="Permalink to &quot;S2S &amp; both $idfa AND $aaid&quot;">​</a></h2><p>The error could also be: (<code>$idfa\\_sha1</code> AND <code>$aaid\\_sha1</code>) or (<code>$idfa\\_md5</code> AND <code>$aaid\\_md5</code>).</p><h4 id="cause-2" tabindex="-1">Cause <a class="header-anchor" href="#cause-2" aria-label="Permalink to &quot;Cause&quot;">​</a></h4><p>Server to server clicks can&#39;t have device IDs for both IDFA and AAID. Because S2S clicks don&#39;t have user agents, Branch uses the presence of a device ID to set the operating system.</p><h4 id="fix-2" tabindex="-1">Fix <a class="header-anchor" href="#fix-2" aria-label="Permalink to &quot;Fix&quot;">​</a></h4><p>Remove one of the device ID macros (e.g. <code>$idfa</code>, <code>$aaid</code>, <code>$idfa\\_sha1</code>, <code>$aaid\\_md5</code>) that are present on this link so there is only one macro present.</p>',18)])])}const m=a(i,[["render",n]]);export{f as __pageData,m as default};
